INSERT INTO `ai_interview_note` VALUES (1,22,18,'技术能过关，表达不行，感觉是懂的但是描述不清楚','刘洋在技术方面展现出较强的能力，尤其是在项目经验上。但是，在沟通表达方面存在不足，虽然对问题的理解是准确的，但在描述解决方案时不够清晰流畅。此外，他拥有处理高并发场景的经验，但这一部分需要进一步验证以确保与岗位需求相匹配。',75,2,'{\"专业技能\": 82, \"团队合作\": 70, \"学习能力\": 80, \"沟通表达\": 65, \"逻辑思维\": 76}','[\"项目经验丰富\", \"技术理解深刻\", \"表述不清需改进\"]',NULL,'2026-07-01 15:59:38','2026-07-01 15:59:38',0),(2,23,17,'还可以期望薪资中规中矩，可以用','候选人刘洋在项目经验方面表现突出，能够清晰地阐述过往项目的挑战及解决方案。沟通表达能力良好但有提升空间，特别是在解释复杂概念时。逻辑思维较强，能够合理规划个人职业发展路径。团队合作经历丰富，展示了良好的解决问题技巧。学习能力强，对于新技术保持高度好奇并愿意投入时间掌握。',82,1,'{\"专业技能\": 85, \"团队合作\": 75, \"学习能力\": 88, \"沟通表达\": 78, \"逻辑思维\": 80}','[\"量化成果意识强\", \"高并发经验需进一步验证\"]',NULL,'2026-07-01 16:02:23','2026-07-01 16:02:23',0),(3,24,16,'表现还可以，就是说话比较结巴','张伟在项目经验方面表现突出，特别是微服务拆分和分布式事务处理上有着丰富的实战经历。尽管在表述时略显紧张导致说话结巴，但其逻辑清晰、思路明确。对于Spring Cloud相关技术的理解深入，并能结合实际案例进行阐述。不过，在高并发场景下的数据库设计与优化方面提出了较为基础的解决方案，建议进一步考察其具体实施能力。此外，关于Feign的使用经验较少。',82,1,'{\"专业技能\": 85, \"团队合作\": 75, \"学习能力\": 88, \"沟通表达\": 78, \"逻辑思维\": 80}','[\"量化成果意识强\", \"高并发经验需进一步验证\"]',NULL,'2026-07-01 16:08:11','2026-07-01 16:08:11',0);
