INSERT INTO `ai_interview_question` VALUES (1,22,'在你负责的在线协作白板项目中，你是如何实现WebSocket与Canvas的集成来支持多人实时协作的？','技术深度','考察WebSocket和Canvas的具体实现',0,NULL,'2026-07-01 15:58:31','2026-07-01 15:58:31',0),(2,22,'请详细描述你在苏宁易购工作期间，使用Vue.js + Python FastAPI技术栈开发商品管理和库存管理模块时遇到的技术挑战及解决方案。','项目经验','验证实际问题解决能力',1,NULL,'2026-07-01 15:58:31','2026-07-01 15:58:31',0),(3,22,'假设你需要将一个现有的React应用迁移到Vue3，你会如何规划迁移过程并确保平稳过渡？','情景应对','评估迁移策略和技术选型能力',2,NULL,'2026-07-01 15:58:31','2026-07-01 15:58:31',0),(4,22,'你在微服务管理平台项目中使用了Go语言，请分享一下你对Go语言的理解以及它在这个项目中的优势。','技术深度','考察对Go语言的理解和应用场景',3,NULL,'2026-07-01 15:58:31','2026-07-01 15:58:31',0),(5,22,'如果让你设计一个REST API来处理用户注册、登录和权限管理，你会如何设计接口，并说明你的设计思路。','关键技能实操','验证API设计能力和安全性考虑',4,NULL,'2026-07-01 15:58:31','2026-07-01 15:58:31',0),(6,23,'在你的职业生涯中，遇到过哪些团队协作方面的挑战？你是如何解决的？','软技能','验证团队合作与问题解决',0,NULL,'2026-07-01 16:01:38','2026-07-01 16:01:38',0),(7,23,'请分享一个你在项目中遇到的沟通难题，并描述你是如何处理的？','软技能','考察沟通能力与协调技巧',1,NULL,'2026-07-01 16:01:38','2026-07-01 16:01:38',0),(8,23,'你对加入我们公司有什么期望？未来三年内你希望在职业上达到什么样的目标？','职业规划','了解职业发展预期',2,NULL,'2026-07-01 16:01:38','2026-07-01 16:01:38',0),(9,23,'我们的企业文化强调创新、高效和团队合作。你觉得自己的哪些特质能够很好地契合这些文化？','文化契合','评估价值观匹配度',3,NULL,'2026-07-01 16:01:38','2026-07-01 16:01:38',0),(10,23,'你目前的工作地点是南京，如果入职本岗位需要搬迁到上海，你会如何考虑这个问题？','情景应对','考察对工作地点变化的态度',4,NULL,'2026-07-01 16:01:38','2026-07-01 16:01:38',0),(11,23,'请说明你对本岗位的期望薪资范围及依据？','薪资期望','了解薪酬预期与谈判空间',5,NULL,'2026-07-01 16:01:38','2026-07-01 16:01:38',0),(12,24,'请详细描述你在电商订单中台项目中负责的微服务拆分工作，包括遇到的主要挑战及解决方案。','项目经验','验证微服务拆分的实际操作能力',0,NULL,'2026-07-01 16:07:40','2026-07-01 16:07:40',0),(13,24,'在你参与过的项目中，如何保证分布式事务的一致性？可以具体举例说明。','技术深度','考察分布式事务处理能力',1,NULL,'2026-07-01 16:07:40','2026-07-01 16:07:40',0),(14,24,'请解释一下Spring Cloud Config + Bus的工作原理，并分享一个实际应用案例。','技术深度','验证对配置中心的理解和应用',2,NULL,'2026-07-01 16:07:40','2026-07-01 16:07:40',0),(15,24,'假设你正在开发一个高并发场景下的系统，请谈谈你会如何设计和优化数据库查询以提升性能？','情景应对','验证数据库优化与高并发处理能力',3,NULL,'2026-07-01 16:07:40','2026-07-01 16:07:40',0),(16,24,'你在之前的项目中是否使用过Feign进行服务间调用？如果没有，请谈谈你对Feign的理解以及它在微服务架构中的作用。','技术深度','了解候选人对Feign的掌握情况',4,NULL,'2026-07-01 16:07:40','2026-07-01 16:07:40',0);
