INSERT INTO `ai_knowledge_chunk` VALUES (24,23,0,'本系统标准招聘流程如下：\n1. 候选人注册并完善简历，浏览岗位后提交投递。\n2. 系统自动触发 AI 简历解析与人岗匹配，生成匹配分与优劣势分析。\n3. HR 在简历管理页进行初筛，筛选状态包括：1待初筛、2面试中、3已录用、4已淘汰。\n4. 初筛通过后，HR 安排面试并指定面试官。\n5. 面试官完成评价后，HR 根据结果推进录用或淘汰。\n6. 后续可进入 Offer 发放与人才库沉淀（如已启用相关模块）。','[0.0163301, -0.024680719, 0.0034156353, 0.00015593984, 0.020250252, -0.027510652, -0.01922962, -0.0055786776, -0.0047030225, -0.008797145, 0.037067473, -0.003441731, 0.02031984, -0.008066466, 0.020053085, 0.0136973355, 0.02764983, 0.008605777, 0.023033792, -0.026698787, -0.04094123, -0.003865061, -0.026350843, 0.02449515, -0.0062513663, -0.028624067, -0.011441508, -0.036603548, 0.0004921936, -0.020830156, -0.023613695, -0.02498227, -0.024425562, -0.01488034, -0.015576225, -0.04627635, -0.009667002, -0.0061237877, 0.00962061, -0.058407944, 0.010989184, -0.0009474184, 0.0154138515, 0.027209101, 0.005166946, 0.0006973347, -0.030526154, -0.013871307, -0.051495485, -0.006860266, -0.034515895, 0.00074445194, 0.025701351, -0.02316137, 0.0155878225, -0.0059614144, -0.0016092339, -0.034747854, 0.013940895, -0.011418312, -0.009440839, -0.013476972, 0.02044742, -0.036232408, -0.01947318, -0.002890822, -0.012073603, -0.01155169, 0.014833948, 0.026745178, -0.040546898, 0.010270102, 0.0037316831, -0.040384524, -0.026165275, 0.03187153, -0.012015614, 0.029714288, -0.014428015, -0.04288971, -0.023184568, 0.036139626, 0.010734025, -0.019971898, 0.00043021637, -0.0284385, 0.013442177, 0.006581912, -0.027974576, -0.048711948, -0.00071038253, -0.002726999, 0.01488034, 0.003737482, 0.02927356, -0.01941519, -0.0010141074, -0.014323632, -0.016364895, 0.013720532, 0.00387086, 0.00085608347, -0.03732263, 0.024170404, 0.024425562, -0.002322516, -0.0019078846, 0.011737259, 0.0435392, 0.00005590638, -0.050057326, -0.017037584, 0.044490244, 0.0049262857, 0.0022703246, -0.008855136, -0.006692094, 0.00731839, 0.03307773, -0.00810706, -0.019612357, 0.0060773953, -0.0035490133, 0.0028574776, -0.011105164, 0.013418982, -0.008002677, -0.0010