记录和投递单。','[0.0075172, -0.0268421, -0.011374113, 0.021639049, 0.06070227, -0.021397047, 0.012906795, -0.017978763, -0.009266675, 0.013481551, 0.005535805, -0.051546514, 0.05267586, 0.053280864, 0.0267211, 0.009559095, 0.004996341, 0.0023570026, -0.0041770623, 0.0040585822, -0.03182332, -0.035836525, 0.0034434926, 0.013370633, -0.012442958, -0.0741334, -0.005273636, -0.028939454, -0.032488823, -0.0010322916, 0.007502075, 0.017928345, -0.054168206, 0.010345603, -0.008011288, -0.063081965, -0.019955115, -0.009770847, 0.051748183, -0.03373917, 0.009448177, 0.024422076, 0.017605675, 0.045214117, 0.0012661011, 0.0023595234, 0.0041871457, 0.0072550303, -0.026741266, 0.018513184, -0.00073230936, 0.011111944, 0.028233614, -0.042068087, 0.0336585, -0.011999286, 0.017585509, -0.03321483, 0.05993593, -0.030310802, -0.02530942, -0.0068063177, 0.0048224023, -0.05638656, 0.02716477, -0.044891447, 0.0064382725, 0.009654888, 0.03650203, -0.006892027, -0.04569812, -0.020509705, 0.018603936, -0.0018931647, -0.029907465, 0.0029872172, 0.011384197, 0.03630036, -0.036744032, -0.008182706, -0.036038194, 0.045496453, 0.0016587249, -0.04295543, -0.00064439443, -0.014590729, -0.012836211, 0.022203721, -0.026539598, -0.02317173, -0.01612341, -0.013955472, 0.028213447, -0.020418953, 0.020832375, -0.0046106502, -0.011232945, 0.0014532749, 0.014913399, 0.015155401, 0.0044039395, -0.0013612636, -0.008379334, 0.010269977, 0.01747459, -0.018240932, -0.0042148754, 0.0365222, 0.0500945, -0.019269442, -0.010910275, -0.0058736, 0.024079239, -0.047271136, 0.0050996966, -0.01793843, 0.02323223, 0.015246152, 0.022647392, -0.007118904, -0.0026569848, -0.038337216, -0.03888172, 0.0027704234, -0.037671708, 0.004232521, 0.009604471, 0.0018074554, -0.029927632, 0.058443584, -0.0005983888, 0.011001026, 0.005293803, 0.03283166, -0.011676616, 0.003635078, -0.06175095, 0.020015616, -0.050901175, -0.0075172, 0.028072279, -0.015941909, 0.017101504, 0.01876527, -0.020832375, 0.008349083, 0.0005558493, -0.02182055, -0.