INSERT INTO `ai_knowledge_doc` VALUES (23,'标准招聘流程','process','本系统标准招聘流程如下：\r\n\r\n1. 候选人注册并完善简历，浏览岗位后提交投递。\r\n2. 系统自动触发 AI 简历解析与人岗匹配，生成匹配分与优劣势分析。\r\n3. HR 在简历管理页进行初筛，筛选状态包括：1待初筛、2面试中、3已录用、4已淘汰。\r\n4. 初筛通过后，HR 安排面试并指定面试官。\r\n5. 面试官完成评价后，HR 根据结果推进录用或淘汰。\r\n6. 后续可进入 Offer 发放与人才库沉淀（如已启用相关模块）。','classpath:knowledge/01-process-recruitment-flow.md',1,'2026-07-01 16:16:15','2026-07-01 16:16:15',0),(24,'简历筛选状态说明','faq','简历筛选状态枚举：\r\n\r\n- 1 待初筛：候选人已投递，等待 HR 审核。\r\n- 2 面试中：已通过初筛并进入面试环节。\r\n- 3 已录用：候选人已被标记为录用。\r\n- 4 已淘汰：候选人未通过当前流程。\r\n\r\nHR 可在简历详情页更新筛选状态，系统会同步最近一条投递记录阶段。','classpath:knowledge/02-faq-screen-status.md',1,'2026-07-01 16:16:16','2026-07-01 16:16:16',0),(25,'AI 人岗匹配分解读','faq','AI 人岗匹配分范围 0-100，供 HR 初筛参考，不代表最终录用结论。\r\n\r\n一般参考：\r\n\r\n- 80 分及以上：高度匹配，可优先安排面试。\r\n- 60-79 分：中等匹配，建议结合简历细节与岗位要求人工复核。\r\n- 60 分以下：匹配度偏低，可重点关注劣势项或谨慎推进。\r\n\r\n匹配结果还包含：匹配等级、优势项、不足项、维度分（技能/经验/学历等）及建议面试题。\r\n\r\n若投递后暂无匹配分，可能是 AI 解析或匹配任务尚未完成，请稍后刷新。','classpath:knowledge/03-faq-match-score.md',1,'2026-07-01 16:16:16','2026-07-01 16:16:16',0),(26,'AI 招聘助手使用指南','faq','AI 招聘助手可协助 HR 完成以下工作：\r\n\r\n- 搜索待初筛简历、按姓名查找候选人。\r\n- 查询投递单的 AI 匹配分、优劣势与建议面试题。\r\n- 搜索在招岗位并查看 JD 详情。\r\n- 查询面试安排。\r\n- 解答招聘流程、筛选状态、匹配分含义等制度与 FAQ 问题。\r\n- 撰写或优化岗位 JD、生成面试题、提供招聘策略建议。\r\n\r\n涉及实时业务数据的问题，助手会先查询系统再回答，不会编造候选人或分数。','classpath:knowledge/04-faq-assistant-guide.md',1,'2026-07-01 16:16:17','2026-07-01 16:16:17',0),(27,'Offer 审批制度','policy','Offer 发放与审批流程：\r\n\r\n1. HR 在候选人通过所有面试环节后，发起 Offer 流程。\r\n2. 填写 Offer 信息：薪资结构、入职日期、试用期、福利待遇等。\r\n3. HRBP 进行一级审批，审核薪资合理性、职级匹配度。\r\n4. 部门负责人进行二级审批，确认岗位需求与候选人匹配。\r\n5. 审批全部通过后，HR 可通过系统向候选人发送 Offer 通知。\r\n6. 候选人可在候选人端查看 Offer 详情并确认接受或拒绝。\r\n7. 候选人接受后，进入入职准备阶段（提交入职材料、背调等）。\r\n\r\n注意：\r\n- Offer 一旦发出后不可随意修改，如需调整需撤回重发。\r\n- 审批超时需主动提醒对应审批人。\r\n- 薪资信息属于敏感数据，仅限 HR、HRBP 及审批人可见。','classpath:knowledge/05-policy-offer-approval.md',1,'2026-07-01 16:16:17','2026-07-01 16:16:17',0),(28,'数据隐私与权限制度','policy','系统数据权限与隐私保护规定：\r\n\r\n角色与权限：\r\n- HR：可查看全部简历、投递记录、匹配分、面试安排，可操作筛选状态和发起 Offer。\r\n- HRBP：可查看本部门相关的面试及 Offer 审批，可查看对应简历。\r\n- 部门负责人：可查看本部门岗位的候选人信息，参与面试评价和 Offer 审批。\r\n- 面试官：可查看被分配的面试候选人简历，提交面试评价。\r\n- 候选人：仅可查看自己的投递状态、面试安排和 Offer 信息。\r\n\r\n数据保护：\r\n- 简历附件存储于 MinIO 对象存储，通过临时签名链接预览，不可直接下载。\r\n- 所有涉及候选人隐私的数据（手机号、邮箱）在前端默认脱敏展示。\r\n- AI 匹配分仅作为参考依据，不作为录用决策的唯一标准。\r\n- 日志系统记录所有关键操作（查看简历、修改状态、发送 Offer 等），可用于审计。\r\n\r\n权限变更需由系统管理员在管理后台操作。','classpath:knowledge/06-policy-data-privacy.md',1,'2026-07-01 16:16:18','2026-07-01 16:16:18',0),(29,'面试流程详解','process','面试安排与执行流程：\r\n\r\n1. 初筛通过后，HR 在「投递管理」中创建面试安排：\r\n   - 选择面试类型：电话面试 / 视频面试 / 线下面试。\r\n   - 指定面试官（可从系统人才库中选择）。\r\n   - 设置面试时间、时长、面试地点或视频链接。\r\n   - 可附加面试重点或备注。\r\n\r\n2. 面试通知：\r\n   - 系统自动向候选人发送面试通知（站内信 / 短信 / 邮件）。\r\n   - 面试官同步收到面试日程提醒。\r\n\r\n3. 面试执行：\r\n   - 面试官在约定时间进行面试。\r\n   - 面后可填写\"面试笔记\"记录关键信息。\r\n   - 面试笔记可提交给 AI 生成评估草稿（基于 AI 面试评估功能）。\r\n\r\n4. 面试评价：\r\n   - 面试官需在面试结束后提交评价：通过 / 待定 / 不通过。\r\n   - 评价维度包括：专业技能、沟通能力、团队匹配度、综合素质。\r\n   - 可填写文字评语与是否推荐进入下一轮。\r\n\r\n5. 多轮面试：\r\n   - 如设有多轮面试（初试 + 复试 + 终试），每轮通过后方可进入下一轮。\r\n   - 多轮面试可指定不同的面试官。\r\n\r\n6. 面试结束后：\r\n   - 全部面试通过 → HR 推进 Offer 流程。\r\n   - 任一环节不通过 → 更新筛选状态为\"已淘汰\"。\r\n   - 可记录淘汰原因，供后续数据分析使用。','classpath:knowledge/07-process-interview-flow.md',1,'2026-07-01 16:16:18','2026-07-01 16:16:18',0),(30,'AI 简历解析功能说明','faq','AI 简历解析是系统自动分析候选人简历的功能：\r\n\r\n工作原理：\r\n- 候选人上传简历（PDF / Word 格式）后，系统自动触发 AI 简历解析。\r\n- 解析使用 Apache Tika 提取文档文本，再由大模型进行结构化处理。\r\n- 提取的信息包括：姓名、联系方式、教育经历、工作经历、技能标签、项目经验等。\r\n\r\n解析结果用途：\r\n- 自动填充候选人简历页面的结构化字段。\r\n- 作为 AI 人岗匹配的输入数据。\r\n- 支持 HR 按技能、学历、工作年限等维度搜索候选人。\r\n\r\n常见问题：\r\n- 解析可能需要几秒到十几秒，视简历复杂度而定。\r\n- 若解析失败，简历页会显示「解析中」或「解析失败」，HR 可手动编辑信息。\r\n- 图片型 PDF / 扫描件解析准确率较低，建议要求候选人上传可编辑格式。\r\n- 解析结果可在「简历详情」页面查看和手动修正。','classpath:knowledge/08-faq-ai-resume-parse.md',1,'2026-07-01 16:16:19','2026-07-01 16:16:19',0),(31,'AI 面试题生成功能说明','faq','AI 面试题生成可以根据岗位要求和候选人简历，自动生成针对性面试问题：\r\n\r\n功能入口：\r\n- 在「面试安排」页面，HR 可为某次面试生成 AI 面试题。\r\n- 系统会根据岗位 JD 和候选人简历，生成个性化面试问题。\r\n\r\n生成内容：\r\n- 技术能力题：基于岗位技能要求，考察候选人的专业技术水平。\r\n- 项目经验题：基于候选人简历中的项目经历，深入追问细节。\r\n- 综合素质题：沟通协作、解决问题能力、抗压能力等软技能问题。\r\n- 岗位匹配题：针对候选人与岗位的匹配薄弱点，设计验证性问题。\r\n\r\n使用建议：\r\n- 面试官可在面试前查看 AI 生成的题目，作为面谈参考。\r\n- 面试题目可自行增删改，灵活调整。\r\n- 生成的题目会持久化保存，关联到具体的面试记录和投递单。','classpath:knowledge/09-faq-ai-interview-question.md',1,'2026-07-01 16:16:20','2026-07-01 16:16:20',0),(32,'面试笔记与 AI 评估功能说明','faq','面试笔记和 AI 评估草稿用于辅助面试官记录面试过程并生成结构化评估：\r\n\r\n面试笔记：\r\n- 面试官在面试结束后，可在「面试记录」页面填写面试笔记。\r\n- 笔记内容包括：面试要点记录、候选人亮点、待考察问题、总体印象等。\r\n- 笔记可随时保存修改，多轮面试分别记录。\r\n\r\nAI 评估草稿：\r\n- 提交面试笔记后，可触发 AI 生成评估草稿。\r\n- AI 会结合面试笔记内容和候选人简历、岗位要求等，生成结构化评估。\r\n- 评估草稿包含：综合评分、各维度评价、推荐建议、风险提示等。\r\n\r\n注意事项：\r\n- AI 评估草稿仅供面试官参考，最终录用决策由 HR 和面试官共同作出。\r\n- 面试笔记和评估草稿仅对 HR 和该场面试的面试官可见。\r\n- 评估草稿可在提交前进行编辑修改。','classpath:knowledge/10-faq-interview-note.md',1,'2026-07-01 16:16:20','2026-07-01 16:16:20',0),(33,'简历质量评分说明','faq','简历质量评分（Resume Quality Score）是 AI 对候选人简历本身质量的量化评估：\r\n\r\n评分维度：\r\n- 信息完整度：联系方式、教育经历、工作经历是否填写完整。\r\n- 内容丰富度：项目经验、技能描述的详细程度。\r\n- 格式规范性：简历结构是否清晰、逻辑是否通顺。\r\n- 专业匹配度：简历内容与求职方向的关联程度。\r\n\r\n分数参考：\r\n- 80 分及以上：简历质量优秀，信息完整，描述详细。\r\n- 60-79 分：简历质量良好，可进一步补充细节。\r\n- 40-59 分：简历信息不足，建议候选人完善后再投递。\r\n- 40 分以下：简历信息严重缺失。\r\n\r\n使用方式：\r\n- HR 可在简历详情页查看简历质量评分。\r\n- 低分简历可建议候选人完善后再评估匹配分。\r\n- 简历质量评分与 AI 人岗匹配分是两个独立的维度，质量评分评价简历本身，匹配分评价与岗位的契合度。\r\n\r\n可通过接口触发重新评分：POST /api/ai/resume-score/evaluate','classpath:knowledge/11-faq-resume-quality-score.md',1,'2026-07-01 16:16:21','2026-07-01 16:16:21',0),(34,'AI 人才画像功能说明','faq','AI 人才画像（Talent Profile）是基于候选人简历和投递数据生成的综合评价画像：\r\n\r\n功能说明：\r\n- AI 自动读取候选人简历内容和历史投递匹配记录，生成人才综合评价。\r\n- 画像内容包含：核心优势、技能雷达、适合岗位方向、发展潜力评估等。\r\n- 只需候选人完成一次投递，即可触发 AI 生成人才画像。\r\n\r\n查看入口：\r\n- 在候选人简历详情页中可查看 AI 人才画像。\r\n- 按投递单 ID 可通过接口查询对应的人才画像。\r\n\r\n用途：\r\n- 帮助 HR 快速了解候选人综合能力，节约筛选时间。\r\n- 当候选人投递多个岗位时，可对照画像判断更适合的方向。\r\n- 画像数据可用于人才库的智能检索和推荐。\r\n\r\n可通过接口生成或刷新画像：POST /api/ai/profile/generate','classpath:knowledge/12-faq-talent-profile.md',1,'2026-07-01 16:16:21','2026-07-01 16:16:21',0),(35,'HR 工作台操作指南','process','HR 工作台是 HR 日常处理招聘工作的核心页面，包含以下功能模块：\r\n\r\n1. 驾驶舱（Dashboard）：\r\n   - 展示本月招聘数据概览：新投递数、面试安排数、录用数、淘汰数。\r\n   - 各部门招聘进度对比图表。\r\n   - 招聘趋势折线图。\r\n\r\n2. 简历管理：\r\n   - 查看所有候选人简历列表，支持按姓名、筛选状态、投递时间筛选。\r\n   - 点击简历可查看详情、简历附件、AI 解析结果、人才画像等。\r\n   - 可更新筛选状态（1待初筛 / 2面试中 / 3已录用 / 4已淘汰）。\r\n\r\n3. 岗位管理：\r\n   - 创建和编辑在招岗位，编写岗位 JD（可借助 AI 助手生成）。\r\n   - 设置岗位状态（在招 / 关闭）。\r\n   - 查看各岗位的投递人数和进度。\r\n\r\n4. 面试管理：\r\n   - 创建、查看、编辑面试安排。\r\n   - 查看各场面试的评价和状态。\r\n   - 使用 AI 面试题生成和面试评估功能。\r\n\r\n5. AI 助手：\r\n   - 智能对话查询各类招聘数据。\r\n   - 可搜索简历、查匹配分、查面试安排等。\r\n   - 可直接让 AI 撰写或优化 JD。','classpath:knowledge/13-process-hr-workbench.md',1,'2026-07-01 16:16:22','2026-07-01 16:16:22',0),(36,'JD 模板：Java 开发工程师','jd_template','岗位名称：Java 开发工程师\r\n\r\n岗位职责：\r\n1. 负责公司核心业务系统的后端设计与开发，保证系统的高可用和高性能。\r\n2. 参与系统架构设计、技术方案评审及代码审查。\r\n3. 根据产品需求完成功能模块的设计、编码、测试和上线。\r\n4. 持续优化现有系统性能，排查和解决线上问题。\r\n5. 编写和维护相关技术文档。\r\n\r\n任职要求：\r\n1. 本科及以上学历，计算机相关专业，3年以上 Java 开发经验。\r\n2. 扎实的 Java 基础，熟悉 Spring Boot / Spring Cloud 微服务体系。\r\n3. 熟悉 MySQL、Redis、消息队列等常用中间件。\r\n4. 具备良好的系统设计能力和问题分析能力。\r\n5. 有分布式系统开发经验者优先。\r\n6. 良好的沟通表达能力和团队协作精神。\r\n\r\n加分项：\r\n- 有 SaaS 平台开发经验。\r\n- 了解 Docker、Kubernetes 等容器化技术。\r\n- 熟悉 AI / 大数据相关技术栈。','classpath:knowledge/14-jd-template-java-developer.md',1,'2026-07-01 16:16:22','2026-07-01 16:16:22',0),(37,'JD 模板：高级产品经理','jd_template','岗位名称：高级产品经理\r\n\r\n岗位职责：\r\n1. 负责产品的需求分析、功能规划和版本迭代管理。\r\n2. 深入理解用户需求，撰写高质量的产品需求文档（PRD）。\r\n3. 协调设计、研发、测试等团队，推动产品从概念到上线。\r\n4. 通过数据分析和用户反馈，持续优化产品体验。\r\n5. 跟踪行业动态和竞品发展，提出产品创新方向。\r\n\r\n任职要求：\r\n1. 本科及以上学历，5年以上互联网产品经理经验。\r\n2. 有从0到1的产品孵化经验，熟悉产品全生命周期管理。\r\n3. 具备优秀的数据分析能力，能通过数据驱动产品决策。\r\n4. 优秀的跨团队沟通协调能力和项目管理能力。\r\n5. 熟练使用 Axure、Figma 等原型设计工具。\r\n6. 有 B2B / SaaS 产品经验者优先。\r\n\r\n加分项：\r\n- 有 AI 产品相关经验。\r\n- 了解技术实现原理，能与开发团队高效协作。\r\n- 有招聘 / HR 领域产品经验。','classpath:knowledge/15-jd-template-product-manager.md',1,'2026-07-01 16:16:22','2026-07-01 16:16:22',0),(38,'JD 模板：前端开发工程师','jd_template','岗位名称：前端开发工程师\r\n\r\n岗位职责：\r\n1. 负责 Web 前端页面的开发、优化和维护。\r\n2. 与 UI 设计师和后端工程师紧密配合，实现高质量的产品界面。\r\n3. 封装和维护前端公共组件，提升团队开发效率。\r\n4. 关注前端性能优化，提升页面加载速度和用户体验。\r\n5. 研究和引入前端新技术，推动技术升级。\r\n\r\n任职要求：\r\n1. 本科及以上学历，3年以上前端开发经验。\r\n2. 精通 HTML5、CSS3、JavaScript / TypeScript。\r\n3. 熟练使用 Vue.js 或 React 框架，有实际项目经验。\r\n4. 熟悉前端工程化工具（Vite / Webpack）和包管理工具。\r\n5. 了解 HTTP 协议和浏览器渲染原理。\r\n6. 有良好的代码规范和文档习惯。\r\n\r\n加分项：\r\n- 有 Node.js 服务端开发经验。\r\n- 了解微前端架构。\r\n- 有数据可视化（ECharts / D3.js）开发经验。','classpath:knowledge/16-jd-template-frontend-developer.md',1,'2026-07-01 16:16:23','2026-07-01 16:16:23',0),(39,'候选人端使用指南','faq','候选人端功能说明：\r\n\r\n功能模块：\r\n1. 注册登录：候选人需注册账号并登录后才能投递岗位。\r\n2. 简历管理：可上传简历、编辑个人信息、完善教育和工作经历。\r\n3. 岗位浏览：查看所有在招岗位，支持按关键词搜索和筛选。\r\n4. 岗位投递：选择感兴趣的岗位提交投递，可查看投递后系统返回的 AI 匹配预览分。\r\n5. 投递进度：查看投递状态（初筛中 / 面试中 / 已录用 / 已淘汰）和面试安排。\r\n6. 面试管理：查看面试通知，含时间、方式、面试官信息等。\r\n7. Offer 查看：如已通过全部面试，可在此查看和确认 Offer。\r\n\r\n常见问题：\r\n- 投递后无法修改简历内容，如需更新请撤回投递后重新提交。\r\n- 匹配预览分仅供参考，正式匹配分在 HR 审核后生成。\r\n- 面试通知会通过站内信发送，请及时查收。\r\n- 如有多个投递，每个投递独立管理，互不影响。','classpath:knowledge/17-faq-candidate-guide.md',1,'2026-07-01 16:16:23','2026-07-01 16:16:23',0),(40,'候选人淘汰原因分类','policy','候选人在各环节被淘汰时，HR 应填写淘汰原因，便于后续数据分析：\r\n\r\n淘汰环节与常见原因：\r\n- 初筛阶段：\r\n  - 简历与岗位要求不匹配\r\n  - 学历或工作年限不达标\r\n  - 技能方向不符\r\n  - 简历信息不完整或虚假\r\n\r\n- 面试阶段：\r\n  - 专业技能不达标\r\n  - 沟通表达能力不足\r\n  - 团队匹配度不够\r\n  - 薪资期望差距过大\r\n  - 候选人主动放弃\r\n\r\n- Offer 阶段：\r\n  - 候选人拒绝 Offer\r\n  - 背调不通过\r\n  - 候选人入职前放弃\r\n\r\n操作规范：\r\n- 淘汰原因应在更新筛选状态时同步填写。\r\n- 规范化的淘汰原因有助于生成招聘分析报告。\r\n- 被淘汰的候选人简历将进入人才库沉淀，后续可再次匹配新岗位。','classpath:knowledge/18-policy-elimination-reason.md',1,'2026-07-01 16:16:24','2026-07-01 16:16:24',0);
/*!40000 ALTER TABLE `ai_knowledge_doc` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `ai_match_record`
--

DROP TABLE IF EXISTS `ai_match_record`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ai_match_record` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '??',
  `application_id` bigint unsigned DEFAULT NULL COMMENT '??ID?????????',
  `job_id` bigint unsigned NOT NULL COMMENT '??ID?????->job??',
  `resume_id` bigint unsigned NOT NULL COMMENT '??ID?????->resume??',
  `model_id` bigint unsigned DEFAULT NULL COMMENT '??ID',
  `match_score` tinyint NOT NULL DEFAULT '0' COMMENT '???0-100',
  `match_status` tinyint NOT NULL DEFAULT '0' COMMENT '0-??? 1-??? 2-?? 3-??',
  `match_level` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '????',
  `match_reason` text COLLATE utf8mb4_unicode_ci COMMENT '????',
  `advantages` json DEFAULT NULL COMMENT '????',
  `disadvantages` json DEFAULT NULL COMMENT '????',
  `suggested_questions` json DEFAULT NULL COMMENT '??????',
  `dimension_scores` json DEFAULT NULL COMMENT '?????',
  `token_used` int NOT NULL DEFAULT '0' COMMENT 'Token??',
  `error_message` varchar(512) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '????',
  `started_at` datetime DEFAULT NULL COMMENT '????',
  `finished_at` datetime DEFAULT NULL COMMENT '????',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '????',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '????',
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '????',
  PRIMARY KEY (`id`),
  KEY `idx_application_id` (`application_id`),
  KEY `idx_job_resume` (`job_id`,`resume_id`),
  KEY `idx_match_score` (`match_score`),
  KEY `idx_match_status` (`match_status`),
