INSERT INTO `ai_match_record` VALUES (13,NULL,3,8,NULL,85,2,'强烈推荐','候选人具备丰富的全栈开发经验，技术栈广泛，且有多个独立负责项目的经验。虽主要技能与岗位要求略有差异，但学习能力强，适应新技术快。','[\"拥有超过2年的全栈开发经验\", \"曾使用Vue.js进行大型项目开发\", \"良好的前后端架构设计能力\"]','[\"主要擅长的技术栈（React, Node.js）与岗位需求（Vue3, Java/Spring Boot）不完全一致\", \"当前工作地点不在上海，可能存在搬迁顾虑\"]','[\"请分享一个你用Vue.js完成的最复杂的项目案例。\", \"对于Java和Spring Boot框架，你的熟悉程度如何？是否有实际项目应用经验？\", \"在面对新技术时，你是如何快速掌握并应用于实践中的？可以举个例子吗？\", \"描述一次你需要同时处理前端和后端问题的经历，以及你是如何解决这些问题的。\", \"谈谈你对微服务架构的理解及其在之前工作中的具体应用。\"]','{\"skill\": 90, \"education\": 75, \"experience\": 80}',0,NULL,'2026-07-01 15:51:50','2026-07-01 15:52:05','2026-07-01 15:51:49','2026-07-01 15:52:04',0),(14,38,3,8,NULL,85,2,'强烈推荐','候选人拥有丰富的全栈开发经验和多个项目交付经历，技术栈虽不完全一致但具备快速学习新技能的能力。','[\"四年全栈开发经验，有多个从0到1的项目完整交付经验\", \"良好的前后端架构设计能力和团队协作精神\", \"持有AWS认证和软考中级证书，证明了其专业能力\"]','[\"主要技能栈为React + Node.js，与岗位要求的Vue3 + Java有一定差异\", \"目前工作城市为南京，可能需要考虑搬迁至上海\"]','[\"请分享一个你使用过的技术栈与本职位不符但仍成功完成项目的例子。\", \"你是如何保持对新技术的学习热情，并将其应用到实际工作中的？\", \"描述一次你独立负责需求分析、开发及联调的经历。\", \"对于Vue3与Java/Spring Boot框架，你了解多少？是否有计划或已经开始学习这些技术？\", \"面对跨城工作机会，您是如何看待并准备应对可能出现的生活调整问题的？\"]','{\"skill\": 90, \"education\": 75, \"experience\": 80}',0,NULL,'2026-07-01 15:51:51','2026-07-01 15:52:07','2026-07-01 15:51:51','2026-07-01 15:52:06',0),(15,39,8,9,NULL,85,2,'强烈推荐','候选人具备丰富的推荐系统及NLP项目经验，掌握相关技能且拥有硕士学历，符合岗位需求。','[\"拥有推荐系统与NLP领域深度实践经验\", \"参与过多个成功的算法优化案例，证明了其解决问题的能力\", \"学术背景强，有顶会论文发表\"]','[\"当前居住城市不在北京，可能影响入职速度\", \"未明确提到LLM应用经验\"]','[\"请详细介绍您在快手短视频推荐算法中的多目标排序模型设计思路？\", \"您如何评估和改进模型的线上表现？可以分享一些具体案例吗？\", \"对于推荐系统的冷启动问题，您有哪些解决方案或见解？\", \"谈谈您对RAG（Retrieval-Augmented Generation）的理解及其在推荐系统中的潜在应用。\", \"假如加入我们团队后，您计划如何快速适应新环境并贡献自己的力量？\"]','{\"skill\": 90, \"education\": 75, \"experience\": 80}',0,NULL,'2026-07-01 15:52:31','2026-07-01 15:52:47','2026-07-01 15:52:31','2026-07-01 15:52:47',0),(16,NULL,8,9,NULL,85,2,'强烈推荐','候选人具备推荐系统和NLP的丰富经验，熟悉Python及相关技术栈，并有成功的项目落地经历。符合岗位要求。','[\"具有多目标推荐排序模型的设计与优化经验\", \"拥有大规模推荐系统的实际落地案例\", \"硕士学历及发表过顶会论文\"]','[\"工作城市不在北京，可能需要考虑搬迁\", \"没有明确提到RAG或LLM的应用经验\"]','[\"请详细描述您在快手负责的短视频推荐算法优化项目中遇到的主要挑战以及您的解决方案。\", \"您如何评估一个推荐系统的性能？请分享一些具体的指标和方法。\", \"能否谈谈您对RAG（Retrieval-Augmented Generation）的理解及其潜在应用场景？\", \"在网易云音乐期间，您是如何通过特征工程提高推荐点击率的？具体采用了哪些策略和技术？\", \"对于即将加入的新团队，您希望在哪些方面贡献自己的力量并寻求成长？\"]','{\"skill\": 90, \"education\": 75, \"experience\": 80}',0,NULL,'2026-07-01 15:52:35','2026-07-01 15:52:51','2026-07-01 15:52:35','2026-07-01 15:52:50',0),(17,NULL,5,10,NULL,30,2,'暂不匹配','候选人具有丰富的运维及DevOps经验，但缺乏测试开发相关技能和项目经验。','[\"拥有8年IT行业工作经验\", \"熟悉多种自动化运维工具和技术\", \"具备大规模集群管理能力\"]','[\"无直接的测试或测开经验\", \"所掌握的技术栈与岗位需求不符\"]','[\"您是否有意愿转型至测试开发领域？\", \"对于接口测试、自动化测试等领域，您目前了解多少？\", \"能否分享一下您在以往项目中如何保证软件质量的经验？\", \"如果加入我们团队，您计划如何快速适应并掌握所需技能？\", \"请谈谈您对持续集成/持续部署(CI/CD)的理解及其与软件测试的关系。\"]','{\"skill\": 10, \"education\": 75, \"experience\": 20}',0,NULL,'2026-07-01 15:53:04','2026-07-01 15:53:17','2026-07-01 15:53:03','2026-07-01 15:53:16',0),(18,40,5,10,NULL,30,2,'暂不匹配','候选人拥有丰富的运维及DevOps经验，但缺乏测试开发所需的接口测试、自动化测试等技能。','[\"具有较强的自动化工具开发能力\", \"有大规模集群管理和云原生架构迁移经验\", \"良好的项目管理能力和团队协作精神\"]','[\"缺少直接的测试或测开工作经验\", \"不熟悉岗位要求的接口测试和自动化测试技术\"]','[\"请分享一个您在运维过程中遇到的问题以及如何解决它的经历。\", \"您是否有参与过与测试相关的项目？如果有，请描述您的角色和贡献。\", \"您是如何保证系统稳定性和服务可用性的？\", \"对于学习新的技术（如Java/Python用于自动化测试），您的态度是什么样的？\", \"能否谈谈您对持续集成/持续交付的理解及其在实际工作中的应用？\"]','{\"skill\": 20, \"education\": 75, \"experience\": 40}',0,NULL,'2026-07-01 15:53:14','2026-07-01 15:53:25','2026-07-01 15:53:13','2026-07-01 15:53:25',0),(19,41,5,11,NULL,85,2,'强烈推荐','候选人具备丰富的测试经验和自动化测试平台搭建经验，符合岗位对技能和经验的要求。','[\"有5年的软件测试经验，超过最低工作年限要求\", \"精通接口测试、性能测试等岗位所需技能\", \"拥有完整的CI/CD自动化测试流水线搭建经验\"]','[\"现居住地与工作城市不一致，可能需要考虑搬迁问题\", \"主要编程语言为Python而非Java，虽然了解但非专长\"]','[\"请分享一下您在华为云PaaS平台项目中如何提高系统稳定性的具体措施？\", \"您能详细介绍一下基于Jenkins + Docker搭建持续测试平台的过程吗？遇到了哪些挑战？\", \"对于Java或Python自动化脚本，您更倾向于使用哪种？为什么？\", \"请描述一次您独立编写测试用例的经历。\", \"您是如何保证在快速迭代的环境中保持高质量的软件交付的？\"]','{\"skill\": 90, \"education\": 75, \"experience\": 80}',0,NULL,'2026-07-01 15:53:52','2026-07-01 15:54:06','2026-07-01 15:53:52','2026-07-01 15:54:06',0),(20,NULL,5,11,NULL,85,2,'强烈推荐','候选人具备丰富的测试开发经验，掌握多项自动化测试工具及脚本语言，且有实际项目经验支持其能力。虽然工作城市不一致，但总体上非常符合岗位需求。','[\"具有超过最低要求的工作经验\", \"熟悉多种自动化测试工具和技术\", \"在前雇主处成功实施了自动化测试和性能监控\"]','[\"目前所在城市与目标工作城市不符\", \"缺少Java编程的具体案例说明\"]','[\"请详细介绍您在华为期间搭建的自动化测试框架细节？\", \"您是如何利用Jenkins和Docker来优化持续集成/持续部署流程的？\", \"能否分享一次您使用Postman/JMeter进行接口测试时遇到挑战并解决的经历？\", \"对于提高系统稳定性方面，您有哪些具体措施或建议？\", \"未来几年内，您对自己职业发展的规划是什么样的？\"]','{\"skill\": 90, \"education\": 75, \"experience\": 80}',0,NULL,'2026-07-01 15:53:56','2026-07-01 15:54:12','2026-07-01 15:53:55','2026-07-01 15:54:11',0),(21,NULL,2,12,NULL,85,2,'强烈推荐','候选人具备丰富的Java后端开发经验和微服务架构设计能力，熟悉Spring Boot、Spring Cloud等技术栈，并且有相关项目经验。','[\"4年Java后端开发经验，符合岗位要求\", \"具有微服务拆分与Feign联调的实际项目经验\", \"在高并发场景下有优化数据库查询的经验\"]','[\"未明确提及MyBatis-Plus的使用经验\", \"缺少具体面试职位描述中的核心业务模块（如简历、投递）相关经验\"]','[\"请详细介绍一下你在电商订单中台项目中如何进行微服务拆分的具体过程？\", \"你在统一配置中心项目中是如何实现配置动态刷新的？遇到了哪些挑战？\", \"能否分享一下你处理过的最复杂的分布式事务案例？你是如何保证数据一致性的？\", \"对于简历管理这类系统的API设计有什么思路或建议？\", \"请谈谈你在软通动力工作期间，如何利用Spring Boot + MyBatis提高报表模块性能的经历。\"]','{\"skill\": 90, \"education\": 75, \"experience\": 80}',0,NULL,'2026-07-01 16:04:56','2026-07-01 16:05:15','2026-07-01 16:04:55','2026-07-01 16:05:14',0),(22,42,2,12,NULL,90,2,'强烈推荐','候选人具备丰富的Java后端开发经验，熟悉Spring Boot、Spring Cloud等技术栈，并且有微服务拆分与设计的实际项目经历。','[\"4年的Java后端开发经验，超过岗位要求的3年\", \"主导过多个大型项目的微服务化改造，具备实际操作经验\", \"熟练掌握职位描述中提到的所有关键技能\"]','[\"未明确提及使用Feign进行联调的经验\", \"缺乏直接参与简历或投递系统开发的经历\"]','[\"请详细说明您在字节跳动期间负责的电商中台订单系统微服务化改造的具体过程。\", \"能否分享一次您如何解决分布式事务问题的经验？\", \"您是如何保证在高并发情况下数据的一致性的？\", \"您有没有参与过类似招聘流程管理系统的开发？如果有，请描述您的角色和贡献。\", \"对于不熟悉的业务领域（如本岗位涉及的人才招聘流程），您通常会采取哪些方法快速上手并提出有效的解决方案？\"]','{\"skill\": 95, \"education\": 70, \"experience\": 85}',0,NULL,'2026-07-01 16:05:14','2026-07-01 16:05:31','2026-07-01 16:05:13','2026-07-01 16:05:31',0),(23,NULL,2,11,NULL,50,2,'暂不匹配','候选人具有丰富的软件测试经验和自动化测试技能，但缺乏Java后端开发经验及所需的特定技术栈。','[\"拥有构建CI/CD流程的经验\", \"熟悉SQL数据库操作\", \"有性能优化项目经历\"]','[\"无Java开发背景\", \"缺少微服务相关实践经验\"]','[\"您是否有意愿从测试转向开发？为什么？\", \"请描述一次您在工作中使用SQL解决实际问题的经历。\", \"谈谈您对持续集成和持续交付的理解。\", \"如果加入我们团队，您计划如何快速学习掌握Spring Boot等技术？\", \"能否分享一下您过去处理系统性能瓶颈的具体案例？\"]','{\"skill\": 30, \"education\": 80, \"experience\": 40}',0,NULL,'2026-07-01 16:10:48','2026-07-01 16:11:03','2026-07-01 16:10:48','2026-07-01 16:11:02',0),(24,NULL,11,11,NULL,20,2,'暂不匹配','候选人具备丰富的软件测试背景，但缺乏UI设计相关技能和经验。工作地点也不符合要求。','[\"拥有ISTQB高级测试工程师认证，显示了其在测试领域的专业水平\", \"有搭建自动化测试平台的经验，显示出较强的工具使用能力和项目管理能力\", \"在知名公司担任过重要职位，积累了宝贵的行业经验\"]','[\"无任何UI设计相关的技能或项目经验\", \"当前所在城市为成都，而岗位要求的工作地为杭州\"]','[\"您为什么考虑转行到UI设计领域？\", \"您是否有学习过与UI设计相关的课程或技术？\", \"请分享一个您认为自己设计得很好的界面案例（如果有的话）。\", \"您如何处理来自不同部门关于设计方案的意见分歧？\", \"能否谈谈您对未来职业发展的规划？\"]','{\"skill\": 10, \"education\": 60, \"experience\": 15}',0,NULL,'2026-07-01 16:10:48','2026-07-01 16:11:08','2026-07-01 16:10:48','2026-07-01 16:11:07',0),(25,NULL,1,11,NULL,20,2,'暂不匹配','候选人主要经验集中在软件测试领域，缺乏前端开发尤其是Vue3、TypeScript等相关技术栈的经验。','[\"具有较强的自动化测试能力\", \"熟悉CI/CD流程，有助于提高团队整体效率\", \"良好的问题解决能力\"]','[\"无前端开发经验\", \"技能标签与岗位需求不符\"]','[\"您为什么对这个职位感兴趣？\", \"请描述一下您过去项目中使用的技术栈。\", \"您如何快速学习新技能以适应不同的工作要求？\", \"您如何看待从测试工程师转行到前端开发的挑战？\", \"分享一个您通过技术手段显著提高了工作效率的例子。\"]','{\"skill\": 15, \"education\": 65, \"experience\": 10}',0,NULL,'2026-07-01 16:10:48','2026-07-01 16:11:02','2026-07-01 16:10:48','2026-07-01 16:11:02',0),(26,NULL,3,11,NULL,40,2,'暂不匹配','候选人拥有丰富的软件测试背景，但全栈开发所需的技术栈如Vue3和Java/Spring Boot方面经验不足。','[\"具有较强的自动化工具使用能力\", \"有持续集成/持续部署(CI/CD)的经验\", \"具备良好的项目管理和沟通协调能力\"]','[\"缺乏前端（尤其是Vue3）及后端开发（Java/Spring Boot）的实际工作经验\", \"目标职位与申请岗位不一致\"]','[\"您在之前的工作中是如何进行需求分析的？可以分享一个具体的例子吗？\", \"虽然您的主要经验在于软件测试领域，请问您对全栈开发有何了解或兴趣？\", \"请描述一下您使用过哪些技术来支持您的测试工作，并谈谈它们如何帮助到您的日常任务。\", \"假如加入我们团队后需要快速掌握Vue3和Spring Boot相关知识，您打算如何学习这些新技能？\", \"能否举例说明您在过去的工作经历中遇到的最大挑战是什么，以及您是如何克服这个挑战的？\"]','{\"skill\": 30, \"education\": 75, \"experience\": 20}',0,NULL,'2026-07-01 16:10:48','2026-07-01 16:11:03','2026-07-01 16:10:48','2026-07-01 16:11:02',0),(27,NULL,7,11,NULL,20,2,'暂不匹配','候选人专业背景及工作经验集中在软件测试领域，与UI/UX设计师岗位要求不符。','[\"具备较强的技术背景\", \"有丰富的项目经验\", \"沟通表达能力强\"]','[\"缺乏UI/UX设计相关技能\", \"没有相关行业作品集\"]','[\"您为什么对UI/UX设计师这个职位感兴趣？\", \"您之前是否有过任何