--
-- Table structure for table `ai_resume_quality_score`
--

DROP TABLE IF EXISTS `ai_resume_quality_score`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ai_resume_quality_score` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `resume_id` bigint unsigned NOT NULL,
  `candidate_id` bigint unsigned NOT NULL,
  `parse_task_id` bigint unsigned DEFAULT NULL,
  `quality_score` tinyint NOT NULL DEFAULT '0',
  `summary` varchar(512) DEFAULT NULL,
  `strengths` json DEFAULT NULL,
  `weaknesses` json DEFAULT NULL,
  `suggestions` json DEFAULT NULL,
  `dimension_scores` json DEFAULT NULL,
  `model_id` bigint unsigned DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `idx_resume_id` (`resume_id`),
