INSERT INTO `ai_talent_profile` VALUES (1,19,38,'刘洋拥有4年全栈开发经验，精通React + Node.js技术栈，并有多个从0到1的项目完整交付经验。具备良好的前后端架构设计能力和团队协作精神。虽然当前主要技能栈与岗位要求略有差异，但其学习能力强且持有AWS认证和软考中级证书，证明了专业能力。需考虑搬迁至上海。','[\"技术扎实\", \"项目经验丰富\", \"沟通良好\"]',NULL,1,'2026-07-01 15:55:20','2026-07-01 15:55:20',0),(2,19,38,'刘洋拥有4年全栈开发经验，精通React + Node.js技术栈，并有多个从0到1的项目交付经历。虽然当前主要技能与岗位要求的Vue3 + Java有所差异，但他具备快速学习新技能的能力。此外，他还持有AWS认证和软考中级证书，证明了其专业能力。良好的前后端架构设计能力和团队协作精神使其能够独立完成需求分析、开发与联调。但需考虑从南京搬迁至上海的问题。','[\"技术扎实\", \"项目经验丰富\", \"沟通良好\"]',NULL,2,'2026-07-01 15:55:28','2026-07-01 15:55:28',0),(3,19,38,'该候选人具备四年全栈开发经验，精通React + Node.js技术栈，并有多次从0到1的项目交付经历。在前后端架构设计及团队协作方面表现良好，持有AWS认证和软考中级证书。虽然当前主要技能栈与岗位要求存在一定差异，但其快速学习能力较强。面试中展示了深厚的技术功底和丰富的项目经验，但在沟通表达上有待提高。','[\"技术扎实\", \"项目经验丰富\", \"沟通需改进\"]',NULL,3,'2026-07-01 15:59:54','2026-07-01 15:59:54',0),(4,19,38,'刘洋拥有4年全栈开发经验，精通React+Node.js技术栈，并有多个从0到1的项目交付经历。他具备良好的前后端架构设计能力及团队协作精神，持有AWS认证和软考中级证书。尽管其主要技能与岗位要求存在差异，但展现了快速学习新技能的能力。面试中表现出较强的专业技能，但在沟通表达上需进一步提升。','[\"技术扎实\", \"项目经验丰富\", \"学习能力强\"]',NULL,4,'2026-07-01 16:00:55','2026-07-01 16:00:55',0),(5,19,38,'刘洋拥有四年全栈开发经验，精通React + Node.js技术栈，并在多个项目中展现出良好的前后端架构设计能力和团队协作精神。虽然当前技能栈与岗位要求存在差异，但其学习能力强，能够快速掌握新技能。面试中表现出较强的专业技能和丰富的项目经验，但在沟通表达方面有待提升。整体来看，候选人具备较高的发展潜力。','[\"技术扎实\", \"项目经验丰富\", \"学习能力强\"]',NULL,5,'2026-07-01 16:02:35','2026-07-01 16:02:35',0),(6,23,42,'张伟具备4年Java后端开发经验，熟悉Spring Boot、Spring Cloud等技术栈，并有主导微服务拆分与设计的实际项目经历。在字节跳动和美团的工作中积累了丰富的微服务化改造及分布式事务处理经验，能够有效提升系统性能。虽然缺乏直接参与简历或投递系统开发的经历，但其技术扎实、项目经验丰富，且沟通良好，整体上非常适合Java后端开发工程师岗位。','[\"技术扎实\", \"项目经验丰富\", \"沟通良好\"]',NULL,1,'2026-07-01 16:06:32','2026-07-01 16:06:32',0),(7,23,42,'张伟拥有4年的Java后端开发经验，熟悉Spring Boot、Spring Cloud等微服务架构技术栈。他在多个大型项目中主导了微服务拆分与设计工作，展现了优秀的系统设计能力。尽管缺乏直接参与简历或投递系统开发的经验，但其丰富的实战经验和良好的问题解决能力使他成为该岗位的有力竞争者。综合建议进一步考察其具体业务模块开发能力。','[\"技术扎实\", \"项目经验丰富\", \"沟通良好\"]',NULL,2,'2026-07-01 16:06:40','2026-07-01 16:06:40',0),(8,23,42,'该候选人具备4年Java后端开发经验，熟悉Spring Boot、Spring Cloud等技术栈，并有丰富的微服务拆分与设计实战经历。在项目中展现出较强的系统设计和问题解决能力。面试中表现出色，逻辑清晰，但需进一步验证其高并发场景下的数据库设计与优化能力。综合来看，张伟是符合岗位要求的优秀人选。','[\"技术扎实\", \"项目经验丰富\", \"沟通良好\"]',NULL,3,'2026-07-01 16:08:32','2026-07-01 16:08:32',0),(9,25,44,'王强拥有5年的数据分析经验，精通SQL和Python，并且熟练使用Tableau、Power BI等BI工具。他在多个项目中展现出较强的数据分析能力和业务洞察力，如用户画像系统和自动化报表平台的建设。尽管缺乏直接的HR或招聘数据处理经验，但其在招聘漏斗优化等类似项目中的表现证明了他具备解决复杂问题的能力。综合来看，王强是一位技术扎实、项目经验丰富且具有良好沟通能力的候选人。','[\"技术扎实\", \"项目经验丰富\", \"沟通良好\"]',4,1,'2026-07-01 18:30:49','2026-07-01 18:30:49',0),(10,25,44,'王强拥有5年的数据分析经验，精通SQL、Python及多种BI工具，符合岗位技能需求。在拼多多和携程的工作经历中，他展现了出色的数据分析能力，包括通过AB测试优化推荐策略以及建立核心指标体系。此外，他还参与了招聘漏斗优化等类似项目，显示出良好的业务洞察力。虽然缺乏直接的HR或招聘数据处理经验，但其丰富的数据分析背景和项目经验使其成为该职位的理想人选。','[\"技术扎实\", \"项目经验丰富\", \"沟通良好\"]',4,2,'2026-07-01 18:30:54','2026-07-01 18:30:54',0);
